Perfect! I now have a comprehensive understanding of the codebase structure. Let me provide the detailed report:

---

## Comprehensive shadcn/ui Codebase Structure Report

I've thoroughly explored the shadcn/ui component library. Here's everything you need to know about where and how to add new components:

### 1. OVERALL DIRECTORY LAYOUT

```
/apps/v4/                          # Main demo/documentation application
├── registry/new-york-v4/          # The core component library (your focus area)
│   ├── ui/                        # UI components (53 components)
│   ├── examples/                  # Demo examples for each component
│   ├── blocks/                    # Pre-built page templates (dashboards, login forms, etc.)
│   ├── charts/                    # Chart/data visualization components
│   ├── internal/                  # Internal examples (sidebar variations, etc.)
│   ├── lib/                       # Shared utility functions
│   ├── hooks/                     # Custom React hooks
│   └── registry.ts                # Master registry that combines all items
├── components/                    # App-specific components
├── lib/                           # App utilities
├── app/                           # Next.js app directory
├── styles/                        # Global styles
├── components.json                # shadcn configuration file
└── registry.json                  # Generated comprehensive registry (auto-built)

/packages/shadcn/                  # The shadcn CLI package itself
├── src/
│   ├── registry/
│   │   ├── schema.ts              # TypeScript schema definitions for registry items
│   │   └── [other registry logic]
│   ├── commands/                  # CLI commands
│   └── utils/                     # CLI utilities

/templates/                        # Project templates
```

---

### 2. HOW EXISTING UI COMPONENTS ARE STRUCTURED

Components live in `/apps/v4/registry/new-york-v4/ui/`. They follow a consistent pattern:

**File: `/apps/v4/registry/new-york-v4/ui/accordion.tsx`** (67 lines, simple component)
```tsx
"use client"

import * as React from "react"
import { ChevronDownIcon } from "lucide-react"
import { Accordion as AccordionPrimitive } from "radix-ui"

import { cn } from "@/lib/utils"

function Accordion({
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Root>) {
  return <AccordionPrimitive.Root data-slot="accordion" {...props} />
}

function AccordionItem({
  className,
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Item>) {
  return (
    <AccordionPrimitive.Item
      data-slot="accordion-item"
      className={cn("border-b last:border-b-0", className)}
      {...props}
    />
  )
}

function AccordionTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Trigger>) {
  return (
    <AccordionPrimitive.Header className="flex">
      <AccordionPrimitive.Trigger
        data-slot="accordion-trigger"
        className={cn(
          "flex flex-1 items-start justify-between gap-4 rounded-md py-4 text-left text-sm font-medium transition-all outline-none hover:underline focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50 [&[data-state=open]>svg]:rotate-180",
          className
        )}
        {...props}
      >
        {children}
        <ChevronDownIcon className="pointer-events-none size-4 shrink-0 translate-y-0.5 text-muted-foreground transition-transform duration-200" />
      </AccordionPrimitive.Trigger>
    </AccordionPrimitive.Header>
  )
}

function AccordionContent({
  className,
  children,
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Content>) {
  return (
    <AccordionPrimitive.Content
      data-slot="accordion-content"
      className="overflow-hidden text-sm data-[state=closed]:animate-accordion-up data-[state=open]:animate-accordion-down"
      {...props}
    >
      <div className={cn("pt-0 pb-4", className)}>{children}</div>
    </AccordionPrimitive.Content>
  )
}

export { Accordion, AccordionItem, AccordionTrigger, AccordionContent }
```

**Key Patterns:**
- `"use client"` directive at top (React 19 client component)
- Wraps Radix UI primitives and adds Tailwind styling
- Uses `cn()` utility function for class merging (clsx + tailwind-merge)
- `data-slot` attributes for styling hooks
- Exports all sub-components (e.g., AccordionItem, AccordionTrigger)
- Uses CVA (class-variance-authority) for variants when needed

**File: `/apps/v4/registry/new-york-v4/ui/button.tsx`** (65 lines, component with variants)
```tsx
import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"
import { Slot } from "radix-ui"

import { cn } from "@/lib/utils"

const buttonVariants = cva(
  "inline-flex shrink-0 items-center justify-center gap-2 rounded-md text-sm font-medium whitespace-nowrap transition-all outline-none focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50 aria-invalid:border-destructive aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*='size-'])]:size-4",
  {
    variants: {
      variant: {
        default: "bg-primary text-primary-foreground hover:bg-primary/90",
        destructive: "bg-destructive text-white hover:bg-destructive/90 focus-visible:ring-destructive/20 dark:bg-destructive/60 dark:focus-visible:ring-destructive/40",
        outline: "border bg-background shadow-xs hover:bg-accent hover:text-accent-foreground dark:border-input dark:bg-input/30 dark:hover:bg-input/50",
        secondary: "bg-secondary text-secondary-foreground hover:bg-secondary/80",
        ghost: "hover:bg-accent hover:text-accent-foreground dark:hover:bg-accent/50",
        link: "text-primary underline-offset-4 hover:underline",
      },
      size: {
        default: "h-9 px-4 py-2 has-[>svg]:px-3",
        xs: "h-6 gap-1 rounded-md px-2 text-xs has-[>svg]:px-1.5 [&_svg:not([class*='size-'])]:size-3",
        sm: "h-8 gap-1.5 rounded-md px-3 has-[>svg]:px-2.5",
        lg: "h-10 rounded-md px-6 has-[>svg]:px-4",
        icon: "size-9",
        "icon-xs": "size-6 rounded-md [&_svg:not([class*='size-'])]:size-3",
        "icon-sm": "size-8",
        "icon-lg": "size-10",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  }
)

function Button({
  className,
  variant = "default",
  size = "default",
  asChild = false,
  ...props
}: React.ComponentProps<"button"> &
  VariantProps<typeof buttonVariants> & {
    asChild?: boolean
  }) {
  const Comp = asChild ? Slot.Root : "button"

  return (
    <Comp
      data-slot="button"
      data-variant={variant}
      data-size={size}
      className={cn(buttonVariants({ variant, size, className }))}
      {...props}
    />
  )
}

export { Button, buttonVariants }
```

**File: `/apps/v4/registry/new-york-v4/ui/tabs.tsx`** (Complex component with variants, groups, and state)
```tsx
"use client"

import * as React from "react"
