"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"

// ─── Types ────────────────────────────────────────────────────────────────────

type StepperOrientation = "horizontal" | "vertical"
type StepperState = "active" | "completed" | "inactive"

// ─── Contexts ─────────────────────────────────────────────────────────────────

interface StepperContextValue {
  value: number
  onValueChange: (value: number) => void
  orientation: StepperOrientation
}

interface StepperItemContextValue {
  step: number
  state: StepperState
  disabled: boolean
}

const StepperContext = React.createContext<StepperContextValue | null>(null)
const StepperItemContext = React.createContext<StepperItemContextValue | null>(
  null
)

function useStepper() {
  const ctx = React.useContext(StepperContext)
  if (!ctx) {
    throw new Error("Stepper sub-components must be used within a <Stepper>.")
  }
  return ctx
}

function useStepperItem() {
  const ctx = React.useContext(StepperItemContext)
  if (!ctx) {
    throw new Error(
      "StepperItem sub-components must be used within a <StepperItem>."
    )
  }
  return ctx
}

// ─── Stepper ──────────────────────────────────────────────────────────────────

interface StepperProps extends Omit<React.ComponentProps<"div">, "onChange"> {
  /** The index of the currently active step (1-based). */
  value: number
  /** Callback fired when the user clicks a step trigger. */
  onValueChange?: (value: number) => void
  /** Layout direction of the step list. Defaults to `"horizontal"`. */
  orientation?: StepperOrientation
}

function Stepper({
  value,
  onValueChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: StepperProps) {
  const handleValueChange = React.useCallback(
    (step: number) => {
      onValueChange?.(step)
    },
    [onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{ value, onValueChange: handleValueChange, orientation }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal"
            ? "flex-row items-start"
            : "flex-col items-stretch",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ─── StepperItem ──────────────────────────────────────────────────────────────

interface StepperItemProps extends React.ComponentProps<"div"> {
  /** The step number this item represents (1-based). */
  step: number
  /** Prevents the user from clicking this step's trigger. */
  disabled?: boolean
  /** Force this step to render as completed regardless of the current value. */
  completed?: boolean
}

function StepperItem({
  step,
  disabled = false,
  completed,
  className,
  children,
  ...props
}: StepperItemProps) {
  const { value, orientation } = useStepper()

  const isCompleted = completed !== undefined ? completed : step < value
  const isActive = !isCompleted && step === value
  const state: StepperState = isCompleted
    ? "completed"
    : isActive
      ? "active"
      : "inactive"

  return (
    <StepperItemContext.Provider value={{ step, state, disabled }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        data-orientation={orientation}
        data-disabled={disabled ? "" : undefined}
        className={cn(
          "group/stepper-item flex",
          orientation === "horizontal"
            ? "flex-col items-center flex-1"
            : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ───────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange, orientation } = useStepper()
  const { step, state, disabled } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-state={state}
      data-orientation={orientation}
      disabled={disabled}
      onClick={() => !disabled && onValueChange(step)}
      className={cn(
        "inline-flex items-center gap-3 rounded-md outline-none transition-colors",
        "focus-visible:ring-[3px] focus-visible:ring-ring/50 focus-visible:border-ring",
        "disabled:pointer-events-none disabled:opacity-50",
        orientation === "horizontal" && "flex-col",
        className
      )}
      {...props}
    >
      {children}
    </button>
  )
}

// ─── StepperIndicator ─────────────────────────────────────────────────────────

function StepperIndicator({
  className,
  children,
  ...props
}: React.ComponentProps<"span">) {
  const { step, state } = useStepperItem()

  return (
    <span
      data-slot="stepper-indicator"
      data-state={state}
      className={cn(
        "inline-flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-semibold transition-all",
        "data-[state=inactive]:border-border data-[state=inactive]:bg-background data-[state=inactive]:text-muted-foreground",
        "data-[state=active]:border-primary data-[state=active]:bg-primary data-[state=active]:text-primary-foreground",
        "data-[state=completed]:border-primary data-[state=completed]:bg-primary data-[state=completed]:text-primary-foreground",
        className
      )}
      {...props}
    >
      {children ??
        (state === "completed" ? (
          <CheckIcon className="size-4" />
        ) : (
          <span>{step}</span>
        ))}
    </span>
  )
}

// ─── StepperTitle ─────────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  const { state } = useStepperItem()

  return (
    <p
      data-slot="stepper-title"
      data-state={state}
      className={cn(
        "text-sm font-medium leading-tight",
        "data-[state=inactive]:text-muted-foreground",
        "data-[state=active]:text-foreground",
        "data-[state=completed]:text-foreground",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperDescription ───────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  const { state } = useStepperItem()

  return (
    <p
      data-slot="stepper-description"
      data-state={state}
      className={cn(
        "text-xs",
        "data-[state=inactive]:text-muted-foreground/50",
        "data-[state=active]:text-muted-foreground",
        "data-[state=completed]:text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperSeparator ─────────────────────────────────────────────────────────

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      aria-hidden="true"
      className={cn(
        "shrink-0 bg-border transition-colors",
        // Horizontal: a thin horizontal rule that stretches to fill free space,
        // nudged down so it bisects the 2rem (size-8) indicators above it.
        orientation === "horizontal" && "mt-4 mx-2 h-px flex-1 self-start",
        // Vertical: a thin vertical line aligned under the centre of the
        // 2rem-wide (size-8) indicator — centre = 1rem = ms-4.
        orientation === "vertical" && "ms-4 my-1 w-px min-h-4",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperContent ───────────────────────────────────────────────────────────

function StepperContent({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  const { state } = useStepperItem()

  if (state !== "active") return null

  return (
    <div
      data-slot="stepper-content"
      data-state={state}
      className={cn(
        "text-sm text-muted-foreground",
        // Vertical: indent to align with the text that follows the indicator
        // (size-8 = 2rem) + gap-3 (0.75rem) = 2.75rem = ps-11
        orientation === "vertical" ? "ms-11 mt-1 pb-4" : "mt-3 w-full",
        className
      )}
      {...props}
    />
  )
}

// ─── Exports ──────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperIndicator,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}
